#define I 1
#define V 5
#define X 10
#define L 50
#define C 100
#define D 500
#define M 1000

class Solution {
public:

    string intToRoman(int num) {

        const vector<pair<int, string>> roman_symbols{
            {M, "M"}, {M - C, "CM"}, {D, "D"}, {D - C, "CD"}, {C, "C"},
            {C - X, "XC"},  {L , "L"},   {L - X, "XL"}, {X, "X"},   {X - I, "IX"},
            {V, "V"},    {V - I, "IV"},   {I, "I"}
            };

        string myString;

        for(const auto& [value, symbol] : roman_symbols){
            if (num == 0)
                break;

            while(num>= value){
                myString += symbol;
                num -= value;
            }

        }

        return myString;
    }
};
